import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { PiggyBank, Plus, AlertCircle, ArrowUpCircle, ArrowDownCircle, Target } from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [dados, setDados] = useState({
    metaGlobal: 0,
    gastoTotal: 0,
    receitaTotal: 0,
    categorias: []
  });

  useEffect(() => {
    buscarDadosReais();
  }, []);

  async function buscarDadosReais() {
    setLoading(true);
    try {
      // 1. Buscar Proventos (Entradas) - Coluna 'valor'
      const { data: proventos } = await supabase.from('proventos').select('valor');
      const totalProventos = proventos?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;

      // 2. Buscar Compras (Saídas) - Coluna 'valor_total'
      const { data: compras } = await supabase
        .from('compras')
        .select('valor_total, categoria_id')
        .eq('tipo_despesa', 'Gastos Variáveis');
      
      const totalGastos = compras?.reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;

      // 3. Buscar Categorias e Calcular Gastos por cada uma
      const { data: cats } = await supabase.from('categorias').select('*').order('nome', { ascending: true });

      const categoriasComSoma = cats.map(cat => {
        const soma = compras
          ?.filter(compra => compra.categoria_id === cat.id)
          .reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;
        
        return { ...cat, gastoReal: soma };
      });

      // Soma das metas individuais para o Limite Global
      const somaMetas = categoriasComSoma.reduce((acc, cur) => acc + (Number(cur.meta) || 0), 0);

      setDados({
        metaGlobal: somaMetas > 0 ? somaMetas : totalProventos,
        gastoTotal: totalGastos,
        receitaTotal: totalProventos,
        categorias: categoriasComSoma
      });

    } catch (err) {
      console.error("Erro ao carregar dados:", err);
    } finally {
      setLoading(false);
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const porcGlobal = (dados.gastoTotal / dados.metaGlobal) * 100;

  if (loading) return <div className="loading-state">Carregando indicadores...</div>;

  return (
    <div className="orcamento-container fade-in">
      <header className="orcamento-header">
        <h2>Painel de Orçamento</h2>
        <button className="btn-ajuste" onClick={() => window.location.href='/categorias'}>
          <Target size={18} /> Configurar Metas
        </button>
      </header>

      {/* SEÇÃO 1: USO DO LIMITE GLOBAL */}
      <h3 className="section-title">Uso do Limite Global</h3>
      <section className="meta-global-card">
        <div className="meta-info">
          <div className="meta-text">
            <span className="label">Status do Mês</span>
            <h3>{formatMoney(dados.gastoTotal)} <small>/ {formatMoney(dados.metaGlobal)}</small></h3>
          </div>
          <PiggyBank size={40} className="icon-main" />
        </div>
        <div className="progress-wrapper">
          <div className={`progress-fill ${porcGlobal > 100 ? 'over' : ''}`} style={{ width: `${Math.min(porcGlobal, 100)}%` }} />
        </div>
        <div className="meta-footer">
          <span>{porcGlobal.toFixed(1)}% consumido</span>
          <span>Saldo: {formatMoney(Math.max(0, dados.metaGlobal - dados.gastoTotal))}</span>
        </div>
      </section>

      <div className="two-columns-grid">
        {/* SEÇÃO 2: PROVENTOS (ENTRADAS) */}
        <section className="orc-section">
          <h3 className="section-title"><ArrowUpCircle size={18} color="#10b981" /> Proventos</h3>
          <div className="summary-box proventos-bg">
            <span className="label">Receita Acumulada</span>
            <p className="value">{formatMoney(dados.receitaTotal)}</p>
          </div>
        </section>

        {/* SEÇÃO 3: DESPESAS POR CATEGORIA (SAÍDAS) */}
        <section className="orc-section">
          <h3 className="section-title"><ArrowDownCircle size={18} color="#ef4444" /> Despesas</h3>
          <div className="summary-box despesas-bg">
            <span className="label">Gastos Variáveis</span>
            <p className="value">{formatMoney(dados.gastoTotal)}</p>
          </div>
        </section>
      </div>

      <h3 className="section-title" style={{marginTop: '30px'}}>Detalhamento por Categoria</h3>
      <div className="orcamento-grid">
        {dados.categorias.map((cat) => {
          const porc = cat.meta > 0 ? (cat.gastoReal / cat.meta) * 100 : 0;
          return (
            <div key={cat.id} className="categoria-card">
              <div className="cat-header">
                <span className="cat-nome">{cat.nome}</span>
                {cat.gastoReal > cat.meta && cat.meta > 0 && <AlertCircle size={16} color="#ef4444" />}
              </div>
              <div className="cat-body">
                <div className="cat-row">
                  <span>Gasto: <strong>{formatMoney(cat.gastoReal)}</strong></span>
                  <span className="cat-meta-label">Meta: {formatMoney(cat.meta || 0)}</span>
                </div>
                <div className="mini-progress-bg">
                  <div className="mini-progress-fill" style={{ width: `${Math.min(porc, 100)}%`, backgroundColor: cat.cor }} />
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Orcamento;
